-/// Find references to outer scope variables in statements
-fn findOuterRefsInStmts(
-    self: *NativeCodegen,
-    stmts: []ast.Node,
-    method_params: []ast.Arg,
-    captured: *std.ArrayList([]const u8),
-) error{OutOfMemory}!void {
